interface ContentContextType {
  content: ContentState;
  updateContent: (section: keyof ContentState, data: any) => void;
  updateNestedContent: (path: string[], value: any) => void;
  resetContent: () => void;
}

const ContentContext = createContext<ContentContextType | undefined>(undefined);

export const ContentProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [content, setContent] = useState<ContentState>(() => {
    const saved = localStorage.getItem('site_content_v3'); // Incrementando versão do storage
    if (saved) {
        const parsed = JSON.parse(saved);
        // Merge with default to ensure new fields exist if loading old data
        return { ...defaultContent, ...parsed, hero: { ...defaultContent.hero, ...parsed.hero }, global: { ...defaultContent.global, ...parsed.global } };
    }
    return defaultContent;
  });

  useEffect(() => {
    localStorage.setItem('site_content_v3', JSON.stringify(content));
  }, [content]);

  const updateContent = (section: keyof ContentState, data: any) => {
    setContent(prev => ({
      ...prev,
      [section]: { ...prev[section], ...data }
    }));
  };

  const updateNestedContent = (path: string[], value: any) => {
    setContent(prev => {
      const newContent = { ...prev };
      let current: any = newContent;
      for (let i = 0; i < path.length - 1; i++) {
        current = current[path[i]];
      }
      current[path[path.length - 1]] = value;
      return newContent;
    });
  };

  const resetContent = () => {
    setContent(defaultContent);
  };

  return (
    <ContentContext.Provider value={{ content, updateContent, updateNestedContent, resetContent }}>
      {children}
    </ContentContext.Provider>
  );
};

export const useContent = () => {
  const context = useContext(ContentContext);
  if (!context) {
    throw new Error('useContent must be used within a ContentProvider');
  }
  return context;
};

