interface InputGroupProps {
  label: string;
  value: string;
  icon?: React.ReactNode;
  onChange?: (v: string) => void;
  toggle?: {
      value: boolean;
      onToggle: () => void;
  }
}

const InputGroup: React.FC<InputGroupProps> = ({ label, value, icon, onChange, toggle }) => (
    <div>
        <div className="flex justify-between items-center mb-2">
            <label className="text-[10px] uppercase tracking-widest text-white/40 block font-bold">{label}</label>
            {toggle && (
                <button onClick={toggle.onToggle} className={`text-xs ${toggle.value ? 'text-brand-gold' : 'text-white/20'}`} title={toggle.value ? 'Visível' : 'Oculto'}>
                    {toggle.value ? <Eye size={12}/> : <EyeOff size={12}/>}
                </button>
            )}
        </div>
        <div className={`relative ${toggle && !toggle.value ? 'opacity-40 pointer-events-none' : ''}`}>
            {icon && <div className="absolute left-4 top-1/2 -translate-y-1/2 text-white/30">{icon}</div>}
            <input 
                type="text" 
                value={value}
                onChange={(e) => onChange?.(e.target.value)}
                className={`w-full bg-brand-dark border border-white/10 p-3 rounded-xl focus:border-brand-gold outline-none text-xs transition-all text-white/80 focus:bg-white/5 ${icon ? 'pl-10' : ''}`} 
            />
        </div>
    </div>
);

interface TextAreaGroupProps {
  label: string;
  value: string;
  height?: string;
  onChange?: (v: string) => void;
}

const TextAreaGroup: React.FC<TextAreaGroupProps> = ({ label, value, height = 'h-32', onChange }) => (
    <div>
        <label className="text-[10px] uppercase tracking-widest text-white/40 mb-2 block font-bold">{label}</label>
        <textarea 
            value={value}
            onChange={(e) => onChange?.(e.target.value)}
            className={`w-full bg-brand-dark border border-white/10 p-3 rounded-xl focus:border-brand-gold outline-none text-xs transition-all text-white/80 focus:bg-white/5 resize-none ${height}`} 
        />
    </div>
);

interface ColorPickerProps {
  label: string;
  value: string;
  onChange?: (v: string) => void;
}

const ColorPicker: React.FC<ColorPickerProps> = ({ label, value, onChange }) => (
    <div>
        <label className="text-[10px] uppercase tracking-widest text-white/40 mb-2 block font-bold">{label}</label>
        <div className="flex items-center gap-3 bg-brand-dark border border-white/10 p-2 rounded-xl">
            <div className="relative w-8 h-8 rounded-lg overflow-hidden shrink-0">
                <input 
                    type="color" 
                    value={value}
                    onChange={(e) => onChange?.(e.target.value)}
                    className="absolute -top-2 -left-2 w-16 h-16 cursor-pointer" 
                />
            </div>
            <input 
                type="text" 
                value={value}
                onChange={(e) => onChange?.(e.target.value)}
                className="bg-transparent border-none outline-none text-xs text-white/70 font-mono w-full uppercase"
            />
        </div>
    </div>
);

interface ImageUploadProps {
  label: string;
  preview: string;
  onChange?: (url: string) => void;
}

const ImageUpload: React.FC<ImageUploadProps> = ({ label, preview, onChange }) => {

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                if (typeof reader.result === 'string') {
                    onChange?.(reader.result);
                }
            };
            reader.readAsDataURL(file);
        }
    };

    return (
        <div className="mb-4">
            <label className="text-[10px] uppercase tracking-widest text-white/40 mb-2 block font-bold">{label}</label>
            <div className="relative aspect-video rounded-xl overflow-hidden border border-white/10 group bg-brand-dark">
                <img src={preview} className="w-full h-full object-cover opacity-60 group-hover:opacity-40 transition-opacity" />

                <label className="absolute inset-0 flex flex-col items-center justify-center cursor-pointer">
                    <input type="file" className="hidden" accept="image/*" onChange={handleFileChange} />
                    <div className="px-4 py-2 bg-brand-charcoal/90 backdrop-blur border border-white/20 text-white rounded-lg text-[10px] uppercase tracking-widest font-bold hover:bg-brand-gold hover:text-brand-dark hover:border-brand-gold transition-all flex items-center gap-2">
                        <Upload size={14} /> Upload
                    </div>
                    <span className="text-[9px] text-white/50 mt-2">ou arraste um arquivo</span>
                </label>
            </div>
        </div>
    );
};

