      <div className="flex w-full min-h-screen relative overflow-x-hidden">
        {/* SIDEBAR ADMIN (Visible only when logged in) */}
        <AnimatePresence>
            {view === 'admin_panel' && isLoggedIn && (
                <motion.div 
                    initial={{ width: 0, opacity: 0 }}
                    animate={{ width: 450, opacity: 1 }}
                    exit={{ width: 0, opacity: 0 }}
                    transition={{ duration: 0.4, ease: [0.22, 1, 0.36, 1] }} // Ease out cubic
                    className="h-screen sticky top-0 left-0 z-[100] bg-brand-charcoal border-r border-white/10 shadow-2xl overflow-hidden flex-shrink-0"
                >
                    <div className="w-[450px] h-full"> {/* Inner container fixed width */}
                        <AdminArea onLogout={() => { setIsLoggedIn(false); setView('public'); }} />
                    </div>
                </motion.div>
            )}
        </AnimatePresence>

        {/* MAIN CONTENT */}
        <div className="flex-1 relative min-w-0">
            <MainSite onOpenAdmin={() => setView('admin_login')} />
        </div>
      </div>
    </ContentProvider>
  );
};

