import { useContent } from './ContentContext';
import { Service, Testimonial, GalleryImage } from './types';

interface AdminProps {
  onLogout: () => void;
}

type EditorSection = 
  | 'global' 
  | 'navbar'
  | 'hero' 
  | 'concept' 
  | 'shield' 
  | 'services' 
  | 'artlab'
