export const AdminArea: React.FC<AdminProps> = ({ onLogout }) => {
  const [editorSection, setEditorSection] = useState<EditorSection>('global');
  const [showSaveToast, setShowSaveToast] = useState(false);

  // States for complex list editing
  const [editingServiceIndex, setEditingServiceIndex] = useState<number | null>(null);
  const [editingGalleryIndex, setEditingGalleryIndex] = useState<number | null>(null);

  const { content, updateNestedContent } = useContent();

  const editorSectionsList = [
    { id: 'global', label: 'Estilo', icon: Palette },
    { id: 'navbar', label: 'Menu', icon: Menu },
    { id: 'hero', label: 'Capa', icon: Layout },
    { id: 'concept', label: 'Conceito', icon: Sparkles },
    { id: 'shield', label: 'Blindagem', icon: Shield },
    { id: 'services', label: 'Serviços', icon: List },
    { id: 'artlab', label: 'Galeria', icon: ImageIcon },
    { id: 'education', label: 'Cursos', icon: GraduationCap },
    { id: 'about', label: 'Sobre', icon: FileText },
    { id: 'testimonials', label: 'Social', icon: MessageCircle },
    { id: 'faq', label: 'FAQ', icon: CheckCircle2 },
    { id: 'location', label: 'Contato', icon: MapPin },
    { id: 'footer', label: 'Footer', icon: Type },
  ];

  const handleSave = () => {
    setShowSaveToast(true);
    setTimeout(() => setShowSaveToast(false), 3000);
  };

  // Helper function to reorder arrays
  const moveItem = (list: any[], index: number, direction: 'up' | 'down', updatePath: string[]) => {
    if ((direction === 'up' && index === 0) || (direction === 'down' && index === list.length - 1)) return;

    const newList = [...list];
    const targetIndex = direction === 'up' ? index - 1 : index + 1;
    [newList[index], newList[targetIndex]] = [newList[targetIndex], newList[index]];

    updateNestedContent(updatePath, newList);
  };

  return (
    <div className="flex h-screen bg-brand-charcoal border-r border-white/10 shadow-2xl relative z-50">

      {/* 1. Sidebar de Navegação (Ícones) */}
      <div className="w-20 bg-brand-dark flex flex-col items-center py-6 gap-4 border-r border-white/5 shrink-0 z-20">
        <div className="mb-4">
            <div className="w-10 h-10 bg-brand-gold rounded-full flex items-center justify-center font-serif font-bold text-brand-dark text-xl">L</div>
        </div>

        <div className="flex-1 flex flex-col gap-2 w-full px-2 overflow-y-auto no-scrollbar">
            {editorSectionsList.map((section) => (
            <button
                key={section.id}
                onClick={() => {
                    setEditorSection(section.id as EditorSection);
                    setEditingServiceIndex(null);
                    setEditingGalleryIndex(null);
                }}
                title={section.label}
                className={`p-3 rounded-xl transition-all flex flex-col items-center gap-1 group relative ${
                editorSection === section.id 
                    ? 'bg-brand-gold text-brand-dark shadow-[0_0_15px_rgba(212,175,55,0.4)]' 
                    : 'text-white/40 hover:bg-white/5 hover:text-white'
                }`}
            >
                <section.icon size={20} />
                <span className="text-[9px] uppercase font-bold tracking-tighter">{section.label}</span>
                {editorSection === section.id && (
                    <motion.div layoutId="active-pill" className="absolute left-0 top-2 bottom-2 w-1 bg-white rounded-r-full" />
                )}
            </button>
            ))}
        </div>

        <button onClick={onLogout} className="mt-auto p-3 text-red-400 hover:bg-red-500/10 rounded-xl" title="Sair">
            <LogOut size={20} />
        </button>
      </div>

      {/* 2. Área de Edição (Formulários) */}
      <div className="flex-1 w-[380px] bg-brand-charcoal overflow-y-auto custom-scrollbar relative flex flex-col">

        {/* Header Fixo */}
        <div className="sticky top-0 bg-brand-charcoal/95 backdrop-blur-md z-30 p-6 border-b border-white/5 flex justify-between items-center">
            <div>
                <h3 className="font-serif text-xl text-brand-gold">
                    {editorSectionsList.find(s => s.id === editorSection)?.label}
                </h3>
                <p className="text-white/40 text-[10px] uppercase tracking-widest mt-1">Editor em Tempo Real</p>
            </div>
            <button 
                onClick={handleSave}
                className="p-2 bg-brand-gold text-brand-dark rounded-lg hover:scale-105 transition-transform shadow-lg"
                title="Salvar Alterações"
            >
                <Save size={18} />
            </button>
        </div>

        <div className="p-6 pb-24 space-y-8 flex-1">
            {/* 1. GLOBAL */}
            {editorSection === 'global' && (
                <>
                    <div className="space-y-6">
                        <ColorPicker label="Cor Primária (Gold)" value={content.global.primaryColor} onChange={(v) => updateNestedContent(['global', 'primaryColor'], v)} />
                        <ColorPicker label="Cor Secundária (Rose)" value={content.global.secondaryColor} onChange={(v) => updateNestedContent(['global', 'secondaryColor'], v)} />

                        <div className="h-px bg-white/5 my-4" />

                        <ColorPicker label="Fundo Escuro (Principal)" value={content.global.bgDark} onChange={(v) => updateNestedContent(['global', 'bgDark'], v)} />
                        <ColorPicker label="Fundo Médio (Cards)" value={content.global.bgCharcoal} onChange={(v) => updateNestedContent(['global', 'bgCharcoal'], v)} />

                        <div className="h-px bg-white/5 my-4" />

                        <div className="space-y-4">
                            <label className="text-[10px] uppercase tracking-widest text-white/40 font-bold">Estilo dos Botões (Arredondamento)</label>
                            <div className="grid grid-cols-3 gap-2">
                                {[
                                    { label: 'Quadrado', val: 'rounded-none' },
                                    { label: 'Suave', val: 'rounded-xl' },
                                    { label: 'Redondo', val: 'rounded-full' }
                                ].map((opt) => (
                                    <button
                                        key={opt.val}
                                        onClick={() => updateNestedContent(['global', 'borderRadius'], opt.val)}
                                        className={`py-2 text-xs font-bold border ${
                                            content.global.borderRadius === opt.val 
                                            ? 'border-brand-gold bg-brand-gold text-brand-dark' 
                                            : 'border-white/10 text-white/50 hover:border-white/30'
                                        } ${opt.val === 'rounded-full' ? 'rounded-full' : opt.val === 'rounded-xl' ? 'rounded-lg' : 'rounded-none'}`}
                                    >
                                        {opt.label}
                                    </button>
                                ))}
                            </div>
                        </div>

                         <div>
                            <label className="text-[10px] uppercase tracking-widest text-white/40 mb-2 block font-bold">Fonte de Títulos</label>
                            <select 
                                value={content.global.fontHeading}
                                onChange={(e) => updateNestedContent(['global', 'fontHeading'], e.target.value)}
                                className="w-full bg-brand-dark border border-white/10 p-3 rounded-xl focus:border-brand-gold outline-none text-xs text-white/80"
                            >
                                <option value='"Playfair Display", serif'>Serifa (Elegante)</option>
                                <option value='"Montserrat", sans-serif'>Sans-Serif (Moderna)</option>
                            </select>
                         </div>
                    </div>
                </>
            )}

            {/* 2. NAVBAR */}
            {editorSection === 'navbar' && (
                <>
                    <InputGroup label="Nome da Marca" value={content.navbar.brandName} onChange={(v) => updateNestedContent(['navbar', 'brandName'], v)} />
                    <InputGroup label="Subtítulo" value={content.navbar.brandSubtitle} onChange={(v) => updateNestedContent(['navbar', 'brandSubtitle'], v)} />

                    <div className="mt-8 pt-6 border-t border-white/5">
                        <label className="text-[10px] uppercase tracking-widest text-white/40 mb-4 block font-bold">Itens do Menu</label>
                        <div className="space-y-3">
                            {content.navbar.items.map((item, idx) => (
                                <div key={idx} className="flex gap-2 items-center bg-brand-dark p-2 rounded-xl border border-white/5">
                                    <div className="flex flex-col">
                                         <button onClick={() => moveItem(content.navbar.items, idx, 'up', ['navbar', 'items'])} disabled={idx===0} className="text-white/20 hover:text-white disabled:opacity-0"><ArrowUp size={10}/></button>
                                         <button onClick={() => moveItem(content.navbar.items, idx, 'down', ['navbar', 'items'])} disabled={idx===content.navbar.items.length-1} className="text-white/20 hover:text-white disabled:opacity-0"><ArrowDown size={10}/></button>
                                    </div>
                                    <div className="flex-1 space-y-1">
                                        <input 
